 30→}
 31→
 32→.rightPanel {
 33→  grid-area: rightpanel;
 34→  display: flex;
 35→  flex-direction: column;
 36→  min-height: 0;
 37→  overflow-y: auto;
 38→}
 39→
 40→.modelWorkspace {
 41→  display: grid;
 42→  grid-template-columns: minmax(0, 1fr) minmax(300px, 28vw);
 43→  width: 100%;
 44→  height: 100%;
 45→  min-width: 0;
 46→  min-height: 0;
 47→}
 48→
 49→.primaryCanvas {
 50→  min-width: 0;
 51→  min-height: 0;
 52→}
 53→
 54→.preview {
 55→  display: flex;
