  1→import { createContext, useContext, useReducer } from 'react';
  2→import { SKETCH_TOOLS, DEFAULT_SKETCH_ZOOM } from '../domain/defaults';
  3→
  4→const SketchEditorContext = createContext(null);
  5→
  6→function sketchEditorReducer(state, action) {
  7→  switch (action.type) {
  8→    case 'SET_TOOL':
  9→      return {
 10→        ...state,
 11→        activeTool: action.tool,
 12→        toolState: {},
 13→        selectedId: null,
 14→        selectedType: null,
 15→      };
 16→
 17→    case 'SELECT_OBJECT':
 18→      return {
 19→        ...state,
 20→        selectedId: action.id,
 21→        selectedType: action.objectType,
 22→      };
 23→
 24→    case 'DESELECT':
 25→      return {
 26→        ...state,
 27→        selectedId: null,
 28→        selectedType: null,
 29→      };
 30→
 31→    case 'UPDATE_TOOL_STATE':
 32→      return {
 33→        ...state,
 34→        toolState: { ...state.toolState, ...action.payload },
 35→      };
 36→
 37→    case 'SET_VIEWPORT': {
 38→      const vpKey = state.workspaceMode === 'sheet' ? 'sheetViewport' : 'modelViewport';
 39→      return {
 40→        ...state,
 41→        [vpKey]: { ...action.viewport },
 42→      };
 43→    }
 44→
 45→    case 'PAN': {
 46→      const vpKey = state.workspaceMode === 'sheet' ? 'sheetViewport' : 'modelViewport';
 47→      return {
 48→        ...state,
 49→        [vpKey]: {
 50→          ...state[vpKey],
 51→          panX: state[vpKey].panX + action.dx,
 52→          panY: state[vpKey].panY + action.dy,
 53→        },
 54→      };
 55→    }
 56→
 57→    case 'ZOOM': {
 58→      const { zoom, panX, panY } = action;
 59→      const vpKey = state.workspaceMode === 'sheet' ? 'sheetViewport' : 'modelViewport';
 60→      return {
 61→        ...state,
 62→        [vpKey]: { zoom, panX, panY },
 63→      };
 64→    }
 65→
 66→    case 'SET_WORKSPACE_MODE':
 67→      return {
 68→        ...state,
 69→        workspaceMode: action.workspaceMode,
 70→        selectedId: null,
 71→        selectedType: null,
 72→      };
 73→
 74→    case 'SET_ACTIVE_SHEET':
 75→      return {
 76→        ...state,
 77→        activeSheetId: action.sheetId,
 78→        selectedId: null,
 79→        selectedType: null,
 80→      };
 81→
 82→    case 'SET_VIEW':
 83→      return {
 84→        ...state,
 85→        activeView: action.view,
 86→      };
 87→
 88→    case 'SET_ACTIVE_ASSEMBLY':
 89→      return {
 90→        ...state,
 91→        activeAssemblyId: action.assemblyId,
 92→      };
 93→
 94→    case 'ENTER_ASSEMBLY_EDIT':
 95→      return {
 96→        ...state,
 97→        activeAssemblyId: action.assemblyId,
 98→        selectedId: action.assemblyId,
 99→        selectedType: 'assembly',
100→      };
101→
102→    case 'TOGGLE_GRID':
103→      return { ...state, showGrid: !state.showGrid };
104→
105→    case 'TOGGLE_SNAP':
106→      return { ...state, snapEnabled: !state.snapEnabled };
107→
108→    case 'SET_STATUS_MESSAGE':
109→      return { ...state, statusMessage: action.message };
110→
111→    case 'CLEAR_STATUS_MESSAGE':
112→      if (!state.statusMessage) return state;
113→      return { ...state, statusMessage: null };
114→
115→    case 'DISMISS_EMPTY_STATE':
116→      return { ...state, emptyStateDismissed: true };
117→
118→    case 'TOGGLE_MAXIMIZE_PANEL':
119→      return { ...state, maximizedPanel: state.maximizedPanel === action.panel ? null : action.panel };
120→
121→    default:
122→      return state;
123→  }
124→}
125→
126→export function createInitialSketchEditorState() {
127→  return {
128→    activeTool: SKETCH_TOOLS.SELECT,
129→    selectedId: null,
130→    selectedType: null,
131→    toolState: {},
132→    modelViewport: { panX: 400, panY: 300, zoom: DEFAULT_SKETCH_ZOOM },
133→    sheetViewport: { panX: 400, panY: 300, zoom: 2.0 },
134→    workspaceMode: 'model',
135→    activeSheetId: null,
136→    activeView: 'top',
137→    activeAssemblyId: null,
138→    showGrid: true,
139→    snapEnabled: true,
140→    statusMessage: null,
141→    emptyStateDismissed: false,
142→    maximizedPanel: null,
143→  };
144→}
145→
146→export function SketchEditorProvider({ children }) {
147→  const [state, dispatch] = useReducer(
148→    sketchEditorReducer,
149→    null,
150→    createInitialSketchEditorState
151→  );
152→
153→  return (
154→    <SketchEditorContext.Provider value={{ state, dispatch }}>
155→      {children}
156→    </SketchEditorContext.Provider>
157→  );
158→}
159→
160→export function useSketchEditor() {
161→  const ctx = useContext(SketchEditorContext);
162→  if (!ctx) throw new Error('useSketchEditor must be used within SketchEditorProvider');
163→  const { state } = ctx;
164→  const viewport = state.workspaceMode === 'sheet' ? state.sheetViewport : state.modelViewport;
165→  return { ...state, viewport, dispatch: ctx.dispatch };
166→}
