 116→function filterConstraintsForRemovedParts(constraints, idsToRemove) {
 117→  return constraints
 118→    .map((constraint) => {
 119→      // For equal_spacing, remove deleted parts from the partIds list
 120→      if (constraint.type === 'equal_spacing') {
 121→        const filtered = (constraint.partIds || []).filter((id) => !idsToRemove.has(id));
 122→        // Also clear referencePartId if it was removed
 123→        const refCleared = idsToRemove.has(constraint.referencePartId)
 124→          ? null
 125→          : constraint.referencePartId;
 126→        if (filtered.length < 2) return null; // not enough parts left
 127→        return { ...constraint, partIds: filtered, referencePartId: refCleared };
 128→      }
 129→      // Standard constraints: remove if either source or target is deleted
 130→      if (idsToRemove.has(constraint.sourcePartId) || idsToRemove.has(constraint.targetPartId)) {
 131→        return null;
 132→      }
 133→      return constraint;
 134→    })
 135→    .filter(Boolean);
 136→}
