 138→function removePartsAndAssemblies(project, { partIds, assemblyIds }) {
 139→  const idsToRemove = new Set(partIds);
 140→  const assemblyIdSet = new Set(assemblyIds);
 141→
 142→  const childIds = new Set(
 143→    project.parts.filter((part) => idsToRemove.has(part.parentId)).map((part) => part.id)
 144→  );
 145→  for (const childId of childIds) idsToRemove.add(childId);
 146→
 147→  const constraints = filterConstraintsForRemovedParts(
 148→    project.constraints || [],
 149→    idsToRemove
 150→  );
 151→
 152→  return {
 153→    ...project,
 154→    parts: project.parts
 155→      .filter((part) => !idsToRemove.has(part.id))
 156→      .map((part) => {
 157→        if (part.type === 'dimension' && part.boundPartId && idsToRemove.has(part.boundPartId)) {
 158→          return { ...part, boundPartId: null, boundProperty: null, boundAxis: null };
 159→        }
 160→        return part;
 161→      }),
 162→    assemblies: project.assemblies.filter((assembly) => !assemblyIdSet.has(assembly.id)),
 163→    constraints,
 164→  };
 165→}
 166→
 167→function removeObjectArtifacts(project, objectId) {
 168→  const partIds = project.parts
 169→    .filter((part) => part.objectId === objectId)
 170→    .map((part) => part.id);
 171→  const assemblyIds = project.assemblies
 172→    .filter((assembly) => assembly.objectId === objectId)
 173→    .map((assembly) => assembly.id);
 174→
 175→  return removePartsAndAssemblies(project, { partIds, assemblyIds });
 176→}
