 353→function sketchReducer(state, action) {
 354→  switch (action.type) {
 355→    case 'SKETCH_NEW': {
 356→      const newProject = action.project || createSketchProject();
 357→      return {
 358→        project: newProject,
 359→        isDirty: false,
 360→        savedSnapshot: snapshotSketch(newProject),
 361→        history: [],
 362→        future: [],
 363→      };
 364→    }
 365→
 366→    case 'SKETCH_LOAD': {
 367→      const loaded = normalizeSketchObjects(action.project);
 368→      return {
 369→        project: loaded,
 370→        isDirty: false,
 371→        savedSnapshot: snapshotSketch(loaded),
 372→        history: [],
 373→        future: [],
 374→      };
 375→    }
 376→
 377→    case 'PART_ADD': {
 378→      const part = sanitizePart(action.part);
 379→      const assembly = part.assemblyId
 380→        ? state.project.assemblies.find((entry) => entry.id === part.assemblyId)
 381→        : null;
 382→      const nextPart = assembly && assembly.objectId
 383→        ? { ...part, objectId: assembly.objectId }
 384→        : part;
 385→      let nextProject = {
 386→        ...state.project,
 387→        updatedAt: new Date().toISOString(),
 388→        parts: [...state.project.parts, nextPart],
 389→      };
 390→      nextProject = applyConstraints(nextProject);
 391→      return applyUpdate(state, nextProject);
 392→    }
 393→
 394→    case 'PART_UPDATE': {
 395→      const managedObject = getManagedObjectForPart(state.project, action.part.id);
 396→      if (managedObject && !action.allowManagedUpdate) return state;
 397→
 398→      let nextProject = {
 399→        ...state.project,
 400→        updatedAt: new Date().toISOString(),
 401→        parts: state.project.parts.map((part) => {
 402→          if (part.id !== action.part.id) return part;
 403→          const merged = mergePart(part, action.part);
 404→          return merged.type === 'dimension' ? merged : sanitizePart(merged);
 405→        }),
 406→      };
 407→      nextProject = applyConstraints(nextProject);
 408→      nextProject = updateBoundDimensions(nextProject, action.part.id);
 409→      return applyUpdate(state, nextProject);
 410→    }
 411→
 412→    case 'PART_DELETE': {
 413→      const managedObject = getManagedObjectForPart(state.project, action.partId);
 414→      if (managedObject) return state;
 415→
 416→      const partId = action.partId;
 417→      const childIds = new Set(
 418→        state.project.parts.filter((part) => part.parentId === partId).map((part) => part.id)
 419→      );
 420→      const idsToRemove = new Set([partId, ...childIds]);
 421→
 422→      const constraints = filterConstraintsForRemovedParts(
 423→        state.project.constraints || [],
 424→        idsToRemove
 425→      );
 426→
 427→      return applyUpdate(state, {
 428→        ...state.project,
 429→        updatedAt: new Date().toISOString(),
 430→        parts: state.project.parts
 431→          .filter((part) => !idsToRemove.has(part.id))
 432→          .map((part) => {
 433→            if (part.type === 'dimension' && part.boundPartId && idsToRemove.has(part.boundPartId)) {
 434→              return { ...part, boundPartId: null, boundProperty: null, boundAxis: null };
 435→            }
 436→            return part;
 437→          }),
 438→        assemblies: state.project.assemblies.map((assembly) => ({
 439→          ...assembly,
 440→          partIds: assembly.partIds.filter((id) => !idsToRemove.has(id)),
 441→        })),
 442→        constraints,
 443→      });
 444→    }
 445→
 446→    case 'PART_CLONE': {
 447→      const managedObject = getManagedObjectForPart(state.project, action.partId);
 448→      if (managedObject) return state;
 449→
 450→      const part = state.project.parts.find((entry) => entry.id === action.partId);
 451→      if (!part) return state;
 452→
 453→      const idMap = new Map();
 454→      const cloned = clonePart(part, idMap);
 455→      const children = state.project.parts.filter((entry) => entry.parentId === action.partId);
 456→      const clonedChildren = children.map((child) => {
 457→        const clonedChild = clonePart(child, idMap);
 458→        clonedChild.parentId = cloned.id;
 459→        return clonedChild;
 460→      });
 461→
 462→      const newParts = [cloned, ...clonedChildren];
 463→      let assemblies = state.project.assemblies;
 464→      if (part.assemblyId) {
 465→        assemblies = assemblies.map((assembly) => {
 466→          if (assembly.id === part.assemblyId) {
 467→            return {
 468→              ...assembly,
 469→              partIds: [...assembly.partIds, ...newParts.map((entry) => entry.id)],
 470→            };
 471→          }
 472→          return assembly;
 473→        });
 474→        for (const nextPart of newParts) {
 475→          nextPart.assemblyId = part.assemblyId;
 476→        }
 477→      }
 478→
 479→      return applyUpdate(state, {
 480→        ...state.project,
 481→        updatedAt: new Date().toISOString(),
 482→        parts: [...state.project.parts, ...newParts],
 483→        assemblies,
 484→      });
 485→    }
 486→
 487→    case 'ASSEMBLY_ADD':
 488→      return applyUpdate(state, {
