import { generateId } from '@/domain/ids';

function createPartBase(type, overrides = {}) {
  return {
    id: generateId('part'),
    type,
    name: overrides.name || type,
    assemblyId: overrides.assemblyId || null,
    objectId: overrides.objectId || null,
    parentId: overrides.parentId || null,
    role: overrides.role || null,
    generatedRole: overrides.generatedRole || null,
    source: overrides.source || 'manual',
    locked: overrides.locked ?? false,
    sortIndex: overrides.sortIndex ?? 0,
    position: { x: 0, y: 0, z: 0, ...overrides.position },
    rotation: { x: 0, y: 0, z: 0, ...overrides.rotation },
    fill: overrides.fill ?? 'rgba(184, 134, 11, 0.06)',
    stroke: overrides.stroke ?? '#1E2433',
    strokeWidth: overrides.strokeWidth ?? 2,
    ...overrides,
  };
}

export function createPanel(overrides = {}) {
  return createPartBase('panel', {
    name: 'Panel',
    width: 600,
    depth: 400,
    thickness: 18,
    material: 'plywood',
    ...overrides,
  });
}

export function createLeg(overrides = {}) {
  return createPartBase('leg', {
    name: 'Leg',
    width: 40,
    depth: 40,
    height: 720,
    profile: 'square',
    ...overrides,
  });
}

export function createFrame(overrides = {}) {
  return createPartBase('frame', {
    name: 'Frame',
    width: 40,
    height: 60,
    length: 500,
    axis: 'x',
    ...overrides,
  });
}

export function createCutout(overrides = {}) {
  if (!overrides.parentId) throw new Error('Cutout requires a parentId');
  return createPartBase('cutout', {
    name: 'Cutout',
    width: 100,
    height: 50,
    depth: 18,
    offsetX: 0,
    offsetY: 0,
    ...overrides,
  });
}

export function createHole(overrides = {}) {
  if (!overrides.parentId) throw new Error('Hole requires a parentId');
  return createPartBase('hole', {
    name: 'Hole',
    diameter: 35,
    depth: 18,
    offsetX: 0,
    offsetY: 0,
    ...overrides,
  });
}

export function createDimension(overrides = {}) {
  return createPartBase('dimension', {
    name: 'Dimension',
    startPoint: { x: 0, y: 0, z: 0, ...overrides.startPoint },
    endPoint: { x: 0, y: 0, z: 0, ...overrides.endPoint },
    offset: 200,
    textOverride: null,
    boundPartId: null,
    boundProperty: null,
    boundAxis: null,
    fill: 'none',
    stroke: '#1E2433',
    ...overrides,
  });
}

import { generateId } from '@/domain/ids';

export const CONSTRAINT_TYPES = [
  { value: 'attach_face', label: 'Attach to Face' },
  { value: 'align_edge', label: 'Align Edge' },
  { value: 'center_axis', label: 'Center Axis' },
  { value: 'inset_edge', label: 'Inset / Fixed Offset' },
  { value: 'flush_surface', label: 'Flush Surface' },
  { value: 'equal_spacing', label: 'Equal Spacing' },
];

export const ANCHOR_OPTIONS = [
  { value: 'top', label: 'Top' },
  { value: 'bottom', label: 'Bottom' },
  { value: 'left', label: 'Left' },
  { value: 'right', label: 'Right' },
  { value: 'front', label: 'Front' },
  { value: 'back', label: 'Back' },
  { value: 'center', label: 'Center' },
];

export const CENTER_AXIS_OPTIONS = [
  { value: 'both', label: 'Both' },
  { value: 'x', label: 'Horizontal (X)' },
  { value: 'y', label: 'Vertical (Y)' },
];

export const SPACING_AXIS_OPTIONS = [
  { value: 'x', label: 'X' },
  { value: 'y', label: 'Y' },
  { value: 'z', label: 'Z' },
];

export function createConstraint(overrides = {}) {
  return {
    id: generateId('cstr'),
    type: overrides.type || 'attach_face',
    sourcePartId: overrides.sourcePartId || null,
    targetPartId: overrides.targetPartId || null,
    sourceAnchor: overrides.sourceAnchor || 'bottom',
    targetAnchor: overrides.targetAnchor || 'top',
    offset: overrides.offset ?? 0,
    axis: overrides.axis || 'both',
    ...overrides,
  };
}

export function createEqualSpacingConstraint(overrides = {}) {
  return {
    id: generateId('cstr'),
    type: 'equal_spacing',
    partIds: overrides.partIds || [],
    axis: overrides.axis || 'z',
    referencePartId: overrides.referencePartId || null,
    startAnchor: overrides.startAnchor || 'bottom',
    endAnchor: overrides.endAnchor || 'top',
    ...overrides,
  };
}

