  max-width: 280px;
  font-size: 12px;
  line-height: 1.5;
  color: var(--color-text-tertiary);
  text-align: center;
}

.overlayControls {
  position: absolute;
  top: 12px;
  right: 12px;
  display: flex;
  gap: 6px;
  z-index: 5;
}

.overlayBtn {
  height: 30px;
  padding: 0 10px;
  border: 1px solid var(--color-border);
  border-radius: var(--radius-sm);
  background: rgba(255, 255, 255, 0.88);
  color: var(--color-text-primary);
  font-size: 12px;
  font-weight: 600;
  cursor: pointer;
  transition: background var(--duration-fast), border-color var(--duration-fast);
}

.overlayBtn:hover {
  background: white;
  border-color: rgba(0, 0, 0, 0.12);
}

.inspectCard {
  position: absolute;
  top: 50px;
  right: 12px;
  display: flex;
  flex-direction: column;
  gap: 4px;
  min-width: 200px;
  max-width: min(260px, calc(100% - 24px));
  padding: 12px 14px;
  border: 1px solid rgba(184, 134, 11, 0.18);
  border-radius: var(--radius-md);
  background: linear-gradient(180deg, rgba(255, 253, 247, 0.96), rgba(252, 248, 238, 0.92));
  box-shadow: 0 12px 28px rgba(37, 48, 61, 0.14);
  pointer-events: none;
  z-index: 4;
}

.inspectEyebrow {
  font-size: 10px;
  font-weight: 700;
  letter-spacing: 0.08em;
  text-transform: uppercase;
  color: #5F6470;
}

.inspectTitle {
  font-size: 14px;
  font-weight: 700;
  color: #1A1D23;
}

.inspectMeta {
  font-size: 11px;
  color: #5F6470;
}

.inspectGrid {
  display: grid;
  grid-template-columns: minmax(0, 1fr);
  gap: 6px;
  margin-top: 6px;
}

.inspectRow {
  display: flex;
  align-items: baseline;
  justify-content: space-between;
  gap: 12px;
}

.inspectLabel {
  font-size: 11px;
  color: #5F6470;
}

.inspectValue {
  font-size: 12px;
  font-weight: 700;
  color: #1A1D23;
}

