    } catch (err) {
      if (!isFilePickerAbortError(err)) {
        console.error('Failed to open sketch file:', err);
      }
    }
  };

  const handleImportFile = async (e) => {
    const file = e.target.files?.[0];
    if (!file) return;
    try {
      const result = await importSketchProjectFile(file);
      dispatch({ type: 'SKETCH_LOAD', project: result.project });
      setFileHandle(null);
      onClose();
    } catch (err) {
      console.error('Failed to import sketch file:', err);
