        onClose();
      }
    } catch (err) {
      console.error('Failed to load sketch draft:', err);
    }
  };

  const handleDeleteDraft = async (id, name) => {
    if (!window.confirm(`Delete "${name}"?`)) return;
    await deleteSketchProject(id);
