150→/**
151→ * Map plane-local dimensions to part overrides based on plane orientation.
152→ */
153→function computePartOverrides(plane, worldPos, uSize, vSize, partType) {
154→  const { normal } = plane;
155→  const position = { x: worldPos.x, y: worldPos.y, z: worldPos.z };
156→
157→  // Determine which domain axes correspond to u and v
158→  const isHorizontal = Math.abs(normal.z) > 0.5; // +z or -z (ground, top, bottom)
159→  const isXFacing = Math.abs(normal.x) > 0.5; // +x or -x
160→  const isYFacing = Math.abs(normal.y) > 0.5; // +y or -y
161→
162→  if (isHorizontal) {
163→    // Drawing on XY plane (ground/top/bottom)
164→    if (partType === 'panel') {
165→      return { position, width: uSize, depth: vSize, thickness: 18 };
166→    }
167→    if (partType === 'leg') {
168→      return { position, width: uSize, depth: vSize, height: 720 };
169→    }
170→    if (partType === 'frame') {
171→      return { position, length: uSize, width: vSize, height: 60 };
172→    }
173→    return { position, width: uSize, depth: vSize };
174→  }
175→
176→  if (isXFacing) {
177→    // Drawing on YZ plane (left/right faces)
178→    if (partType === 'panel') {
179→      return { position, width: 18, depth: uSize, thickness: vSize };
180→    }
181→    if (partType === 'leg') {
182→      return { position, width: 40, depth: uSize, height: vSize };
183→    }
184→    return { position, width: 18, depth: uSize };
185→  }
186→
187→  if (isYFacing) {
188→    // Drawing on XZ plane (front/back faces)
189→    if (partType === 'panel') {
190→      return { position, width: uSize, depth: 18, thickness: vSize };
191→    }
192→    if (partType === 'leg') {
193→      return { position, width: uSize, depth: 40, height: vSize };
194→    }
195→    return { position, width: uSize, depth: 18 };
196→  }
197→
198→  // Fallback: treat as ground plane
199→  return { position, width: uSize, depth: vSize };
200→}
