 5→/**
 6→ * Maps activeTool to the appropriate 3D handler constructor.
 7→ */
 8→export function create3dHandler(ctx) {
 9→  const { activeTool, drawingPlane } = ctx;
10→
11→  switch (activeTool) {
12→    case 'panel':
13→    case 'leg':
14→    case 'frame':
15→      return createDrawRectHandler3d({ ...ctx, partType: activeTool, drawingPlane });
16→
17→    case 'pushpull':
18→      return createPushPullHandler3d(ctx);
19→
20→    case 'select':
21→    default:
22→      return createSelectHandler3d(ctx);
23→  }
24→}
