 17→/**
 18→ * Primary 3D editing viewport.
 19→ * Wraps createPreviewViewport with tool event routing, raycasting, and overlays.
 20→ */
 21→export default function SketchViewport() {
 22→  const containerRef = useRef(null);
 23→  const viewportRef = useRef(null);
 24→  const rootRef = useRef(null);
 25→  const overlayRef = useRef(null);
 26→  const extrusionPreviewRef = useRef(null);
 27→  const resizeObserverRef = useRef(null);
 28→  const compassNeedleRef = useRef(null);
 29→  const movementPlaneRef = useRef(null);
 30→  const pointerDownRef = useRef(null);
 31→
 32→  const { project, dispatch } = useSketch();
 33→  const {
 34→    activeTool, selectedId, selectedType, toolState,
 35→    activeAssemblyId, snapEnabled, statusMessage,
 36→    drawingPlane, emptyStateDismissed,
 37→    dispatch: editorDispatch,
 38→  } = useSketchEditor();
 39→
 40→  const [cursorCoords, setCursorCoords] = useState({ x: 0, y: 0, z: 0 });
 41→
 42→  const inspection = useMemo(
 43→    () => getSketchInspection(project, selectedId, selectedType),
 44→    [project, selectedId, selectedType]
 45→  );
 46→
 47→  // Build the 3D tool handler
 48→  const tool = useMemo(() => {
 49→    return create3dHandler({
 50→      dispatch,
 51→      editorDispatch,
 52→      project,
 53→      activeTool,
 54→      activeAssemblyId,
 55→      snapEnabled,
 56→      selectedId,
 57→      selectedType,
 58→      drawingPlane: drawingPlane || GROUND_PLANE,
 59→    });
 60→  }, [dispatch, editorDispatch, project, activeTool, activeAssemblyId, snapEnabled, selectedId, selectedType, drawingPlane]);
 61→
 62→  // Parts visible in 3D
 63→  const visibleParts = useMemo(() => {
 64→    return project.parts.filter(
 65→      (part) => part.type !== 'dimension' && part.type !== 'cutout' && part.type !== 'hole'
 66→    );
 67→  }, [project.parts]);
 68→
 69→  // Initialize viewport
 70→  useEffect(() => {
 71→    const container = containerRef.current;
 72→    if (!container) return undefined;
 73→
 74→    const viewport = createPreviewViewport(container);
 75→    viewport.setNavigationMode('inspect');
 76→    viewportRef.current = viewport;
 77→
 78→    // Drawing plane overlay
 79→    const overlay = createDrawingPlaneOverlay();
 80→    overlayRef.current = overlay;
 81→
 82→    // Extrusion preview
 83→    const extPreview = createExtrusionPreview();
 84→    extrusionPreviewRef.current = extPreview;
 85→
 86→    if ('ResizeObserver' in window) {
 87→      const observer = new ResizeObserver(() => viewport.resize());
 88→      observer.observe(container);
 89→      resizeObserverRef.current = observer;
 90→    }
 91→
 92→    viewport.setCompassHeadingHandler((headingDeg) => {
 93→      if (!compassNeedleRef.current) return;
 94→      compassNeedleRef.current.style.setProperty('--compass-heading', `${headingDeg}deg`);
 95→    });
 96→
 97→    // Disable the built-in pick handler since we handle our own events
 98→    viewport.setPickHandler(null);
 99→    viewport.resize();
100→
101→    // Listen for camera preset events from toolbar
102→    const handleCameraPreset = (e) => {
103→      const { preset } = e.detail || {};
104→      if (preset && viewport.setProjectionPreset) {
105→        viewport.setProjectionPreset(preset);
106→      }
107→    };
108→    window.addEventListener('sketch-camera-preset', handleCameraPreset);
109→
110→    return () => {
111→      window.removeEventListener('sketch-camera-preset', handleCameraPreset);
112→      resizeObserverRef.current?.disconnect?.();
113→      resizeObserverRef.current = null;
114→      overlay.dispose();
115→      extPreview.dispose();
116→      if (rootRef.current) {
117→        disposeScene(rootRef.current, { disposeMaterials: true });
118→        rootRef.current = null;
119→      }
120→      viewport.dispose();
121→      viewportRef.current = null;
122→    };
123→  }, []);
124→
125→  // Rebuild scene when parts or selection change
126→  useEffect(() => {
127→    const viewport = viewportRef.current;
128→    if (!viewport) return;
129→
130→    if (rootRef.current) {
131→      disposeScene(rootRef.current, { disposeMaterials: true });
132→    }
133→
134→    const root = buildSketchPreviewRoot(visibleParts, { selectedId, selectedType });
135→    rootRef.current = root;
136→
137→    // Add overlay groups to root
138→    if (overlayRef.current) {
139→      root.add(overlayRef.current.group);
140→    }
141→    if (extrusionPreviewRef.current) {
142→      root.add(extrusionPreviewRef.current.group);
143→    }
144→
145→    const box = new THREE.Box3();
146→    root.updateMatrixWorld(true);
147→    box.expandByObject(root);
148→
149→    if (box.isEmpty()) {
150→      box.set(
151→        new THREE.Vector3(-500, 0, -300),
152→        new THREE.Vector3(500, 800, 300)
153→      );
154→    }
155→
156→    viewport.setWorld(root, {
157→      min: { x: box.min.x, y: box.min.y, z: box.min.z },
158→      max: { x: box.max.x, y: box.max.y, z: box.max.z },
159→    }, 0);
160→  }, [visibleParts, selectedId, selectedType]);
161→
162→  // Update drawing plane overlay
163→  useEffect(() => {
164→    const overlay = overlayRef.current;
165→    if (!overlay) return;
166→
167→    const plane = drawingPlane || GROUND_PLANE;
168→    const isDrawTool = ['panel', 'leg', 'frame'].includes(activeTool);
169→
170→    if (isDrawTool) {
171→      overlay.setPlane(plane, 50, 2000);
172→    } else {
173→      overlay.clearGrid();
174→    }
175→  }, [drawingPlane, activeTool]);
176→
177→  // Update drawing preview rect
178→  useEffect(() => {
179→    const overlay = overlayRef.current;
180→    if (!overlay) return;
181→
182→    if (toolState.drawing && toolState.startLocal && toolState.currentLocal) {
183→      const plane = drawingPlane || GROUND_PLANE;
184→      overlay.setPreviewRect(plane, toolState.startLocal, toolState.currentLocal);
185→    } else {
186→      overlay.clearPreview();
187→    }
188→  }, [toolState.drawing, toolState.startLocal, toolState.currentLocal, drawingPlane]);
189→
190→  // Update extrusion preview
191→  useEffect(() => {
192→    const preview = extrusionPreviewRef.current;
193→    if (!preview) return;
194→
195→    if (toolState.extruding && toolState.sourcePart && toolState.faceId) {
196→      preview.update(toolState.sourcePart, toolState.faceId, toolState.extrusionDistance || 0);
197→    } else {
198→      preview.clear();
199→    }
200→  }, [toolState.extruding, toolState.sourcePart, toolState.faceId, toolState.extrusionDistance]);
201→
202→  // Raycasting helper
203→  const raycast = useCallback((e) => {
204→    const viewport = viewportRef.current;
205→    if (!viewport || !rootRef.current) return null;
206→
207→    const renderer = viewport.getDomElement?.();
208→    const camera = viewport.getCamera?.();
209→    if (!renderer || !camera) return null;
210→
211→    const rect = renderer.getBoundingClientRect();
212→    if (!rect.width || !rect.height) return null;
213→
214→    const pointer = new THREE.Vector2(
215→      ((e.clientX - rect.left) / rect.width) * 2 - 1,
216→      -(((e.clientY - rect.top) / rect.height) * 2 - 1)
217→    );
218→
219→    const raycaster = new THREE.Raycaster();
220→    raycaster.setFromCamera(pointer, camera);
221→
222→    // Raycast against world objects (excluding overlay groups)
223→    const hits = raycaster.intersectObject(rootRef.current, true);
224→
225→    let partId = null;
226→    let objectId = null;
227→    let point = null;
228→    let faceNormal = null;
229→
230→    for (const hit of hits) {
231→      // Skip overlay objects
232→      if (isOverlayObject(hit.object)) continue;
233→
234→      point = { x: hit.point.x, y: hit.point.y, z: hit.point.z };
235→
236→      // Get face normal
237→      if (hit.face) {
238→        const normal = hit.face.normal.clone();
239→        hit.object.updateMatrixWorld();
240→        const normalMatrix = new THREE.Matrix3().getNormalMatrix(hit.object.matrixWorld);
241→        normal.applyMatrix3(normalMatrix).normalize();
242→        faceNormal = { x: normal.x, y: normal.y, z: normal.z };
243→      }
244→
245→      // Resolve to part/object
246→      const target = resolvePickTarget(hit.object);
247→      if (target) {
248→        if (target.kind === 'part') {
249→          partId = target.sourceId;
250→        } else if (target.kind === 'object') {
251→          objectId = target.sourceId;
252→          // Also find a part for the hit
253→          partId = findPartIdFromObjectHit(hit.object, project);
254→        }
255→        break;
256→      }
257→    }
258→
259→    // Compute drawing plane intersection
260→    const plane = drawingPlane || GROUND_PLANE;
261→    const threePlane = domainPlaneToThreePlane(plane);
262→    const drawingPlanePoint3 = new THREE.Vector3();
263→    const hasPlaneHit = raycaster.ray.intersectPlane(threePlane, drawingPlanePoint3);
264→    const drawingPlanePoint = hasPlaneHit
265→      ? { x: drawingPlanePoint3.x, y: drawingPlanePoint3.z, z: drawingPlanePoint3.y } // Three.js -> domain
266→      : null;
267→
268→    // Compute movement plane (camera-perpendicular through drag start or hit point)
269→    const movementOrigin = point || (hasPlaneHit ? { x: drawingPlanePoint3.x, y: drawingPlanePoint3.y, z: drawingPlanePoint3.z } : null);
270→    let planePoint = null;
271→    if (movementOrigin && movementPlaneRef.current) {
272→      const mvPoint = new THREE.Vector3();
273→      if (raycaster.ray.intersectPlane(movementPlaneRef.current, mvPoint)) {
274→        planePoint = { x: mvPoint.x, y: mvPoint.y, z: mvPoint.z };
275→      }
276→    }
277→
278→    // Update cursor coords (convert Three.js -> domain: x=x, y=z, z=y)
279→    if (point) {
280→      setCursorCoords({
281→        x: Math.round(point.x),
282→        y: Math.round(point.z), // Three.js Z = domain Y
283→        z: Math.round(point.y), // Three.js Y = domain Z
284→      });
285→    } else if (drawingPlanePoint) {
286→      setCursorCoords({
287→        x: Math.round(drawingPlanePoint.x),
288→        y: Math.round(drawingPlanePoint.y),
289→        z: Math.round(drawingPlanePoint.z),
290→      });
291→    }
292→
293→    return { partId, objectId, point, faceNormal, drawingPlanePoint, planePoint };
294→  }, [project, drawingPlane]);
295→
296→  // Set up movement plane when drag starts
297→  useEffect(() => {
298→    if (toolState.dragging && toolState.startPoint) {
299→      const viewport = viewportRef.current;
300→      const camera = viewport?.getCamera?.();
301→      if (camera) {
302→        const camDir = new THREE.Vector3();
303→        camera.getWorldDirection(camDir);
304→        const origin = new THREE.Vector3(toolState.startPoint.x, toolState.startPoint.y, toolState.startPoint.z);
305→        movementPlaneRef.current = new THREE.Plane().setFromNormalAndCoplanarPoint(camDir, origin);
306→      }
307→    } else if (!toolState.dragging) {
308→      movementPlaneRef.current = null;
309→    }
310→  }, [toolState.dragging, toolState.startPoint]);
311→
312→  // Pointer event handlers
313→  const handlePointerDown = useCallback((e) => {
314→    // Right-click and middle-click are handled by OrbitControls
315→    if (e.button !== 0) return;
316→
317→    pointerDownRef.current = { x: e.clientX, y: e.clientY };
318→
319→    const intersection = raycast(e);
320→    if (!intersection) return;
321→
322→    // Set up movement plane for drag
323→    if (intersection.point) {
324→      const viewport = viewportRef.current;
325→      const camera = viewport?.getCamera?.();
326→      if (camera) {
327→        const camDir = new THREE.Vector3();
328→        camera.getWorldDirection(camDir);
329→        const origin = new THREE.Vector3(intersection.point.x, intersection.point.y, intersection.point.z);
330→        movementPlaneRef.current = new THREE.Plane().setFromNormalAndCoplanarPoint(camDir, origin);
331→      }
332→    }
333→
334→    tool.onPointerDown(intersection, e, toolState, viewportRef.current);
335→  }, [raycast, tool, toolState]);
336→
337→  const handlePointerMove = useCallback((e) => {
338→    if (e.buttons === 0 && !toolState.dragging && !toolState.drawing && !toolState.extruding) return;
339→
340→    const intersection = raycast(e);
341→    if (!intersection) return;
342→
343→    tool.onPointerMove(intersection, e, toolState, viewportRef.current);
344→  }, [raycast, tool, toolState]);
345→
346→  const handlePointerUp = useCallback((e) => {
347→    if (e.button !== 0) return;
348→
349→    // Check if this was a click vs drag (for OrbitControls compatibility)
350→    const down = pointerDownRef.current;
351→    pointerDownRef.current = null;
352→
353→    if (down) {
354→      const dx = e.clientX - down.x;
355→      const dy = e.clientY - down.y;
356→      if (Math.hypot(dx, dy) > 5 && !toolState.dragging && !toolState.drawing && !toolState.extruding) {
357→        // Was an orbit gesture, not a tool interaction
358→        return;
359→      }
360→    }
361→
362→    const intersection = raycast(e);
363→    tool.onPointerUp(intersection, e, toolState, viewportRef.current);
364→  }, [raycast, tool, toolState]);
365→
366→  const handleDoubleClick = useCallback((e) => {
367→    const intersection = raycast(e);
368→    if (intersection && tool.onDoubleClick) {
369→      tool.onDoubleClick(intersection, e, toolState);
370→    }
371→  }, [raycast, tool, toolState]);
372→
373→  // Keyboard shortcuts
374→  useEffect(() => {
375→    const handleKeyDown = (e) => {
376→      if (e.target.tagName === 'INPUT' || e.target.tagName === 'TEXTAREA' || e.target.isContentEditable) return;
377→
378→      if (e.key === 'Escape') {
379→        if (activeAssemblyId) {
380→          tool.onKeyDown(e, toolState, selectedId);
381→          return;
382→        }
383→        editorDispatch({ type: 'SET_TOOL', tool: 'select' });
384→        return;
385→      }
386→
387→      if (!e.ctrlKey && !e.metaKey) {
388→        const toolKey = SKETCH_TOOL_SHORTCUTS[e.key.toLowerCase()];
389→        if (toolKey) {
390→          editorDispatch({ type: 'SET_TOOL', tool: toolKey });
391→          return;
392→        }
393→
394→        // Push/pull shortcut
395→        if (e.key.toLowerCase() === 'e') {
396→          editorDispatch({ type: 'SET_TOOL', tool: 'pushpull' });
397→          return;
398→        }
399→      }
400→
401→      if ((e.key === 'Delete' || e.key === 'Backspace') && selectedId) {
402→        tool.onKeyDown(e, toolState, selectedId);
403→        return;
404→      }
405→
406→      tool.onKeyDown(e, toolState, selectedId);
407→    };
408→
409→    window.addEventListener('keydown', handleKeyDown);
410→    return () => window.removeEventListener('keydown', handleKeyDown);
411→  }, [editorDispatch, selectedId, activeAssemblyId, tool, toolState]);
412→
413→  // Status message auto-clear
414→  useEffect(() => {
415→    if (!statusMessage) return undefined;
416→    const timer = window.setTimeout(() => {
417→      editorDispatch({ type: 'CLEAR_STATUS_MESSAGE' });
418→    }, 2500);
419→    return () => window.clearTimeout(timer);
420→  }, [statusMessage, editorDispatch]);
421→
422→  // Draw dimension label
423→  const drawDimLabel = toolState.drawing && toolState.startLocal && toolState.currentLocal
424→    ? `${Math.round(Math.abs(toolState.currentLocal.u - toolState.startLocal.u))} x ${Math.round(Math.abs(toolState.currentLocal.v - toolState.startLocal.v))} mm`
425→    : null;
426→
427→  // Extrusion numeric input display
428→  const numericDisplay = toolState.extruding && toolState.numericInput
429→    ? toolState.numericInput
430→    : null;
431→
432→  const extrusionLabel = toolState.extruding && toolState.extrusionDistance
433→    ? `${Math.round(toolState.extrusionDistance)} mm`
434→    : null;
435→
436→  const hasParts = project.parts.length > 0;
437→  const hasAssemblies = project.assemblies.length > 0;
438→  const showEmptyState = !hasParts && !hasAssemblies && !emptyStateDismissed;
439→
440→  return (
441→    <div className={styles.viewport}>
442→      <div
443→        ref={containerRef}
444→        className={styles.canvas}
445→        onPointerDown={handlePointerDown}
446→        onPointerMove={handlePointerMove}
447→        onPointerUp={handlePointerUp}
448→        onDoubleClick={handleDoubleClick}
449→        style={{ cursor: tool.getCursor(toolState) }}
450→      />
451→
452→      <CompassOverlay className={styles.compassDock} needleRef={compassNeedleRef} />
453→
454→      {/* Overlay controls */}
455→      <div className={styles.overlayControls}>
456→        <button
457→          type="button"
458→          className={styles.overlayBtn}
459→          onClick={() => viewportRef.current?.resetView()}
460→        >
461→          Reset View
462→        </button>
463→      </div>
464→
465→      {/* Inspection card */}
466→      {inspection && (
467→        <div className={styles.inspectCard}>
468→          <span className={styles.inspectEyebrow}>{selectedType === 'object' ? 'Selected Object' : 'Selected Part'}</span>
469→          <span className={styles.inspectTitle}>{inspection.title}</span>
470→          <span className={styles.inspectMeta}>{inspection.subtitle}</span>
471→          <div className={styles.inspectGrid}>
472→            {inspection.rows.map((row) => (
473→              <div key={`${inspection.id}-${row.label}`} className={styles.inspectRow}>
474→                <span className={styles.inspectLabel}>{row.label}</span>
475→                <span className={styles.inspectValue}>{row.value}</span>
476→              </div>
477→            ))}
478→          </div>
479→        </div>
480→      )}
481→
482→      {/* Dimension label during draw */}
483→      {drawDimLabel && (
484→        <div className={styles.dimLabel} style={{ bottom: 44, left: '50%', transform: 'translateX(-50%)' }}>
485→          {drawDimLabel}
486→        </div>
487→      )}
488→
489→      {/* Extrusion distance label */}
