576→/**
577→ * Convert a domain drawing plane to a Three.js Plane.
578→ * Domain: x=x, y=y, z=z -> Three.js: x=x, y=z, z=y
579→ */
580→function domainPlaneToThreePlane(plane) {
581→  const threeNormal = new THREE.Vector3(
582→    plane.normal.x,
583→    plane.normal.z, // domain Z -> Three.js Y
584→    plane.normal.y  // domain Y -> Three.js Z
585→  ).normalize();
586→
587→  const threeOrigin = new THREE.Vector3(
588→    plane.origin.x,
589→    plane.origin.z, // domain Z -> Three.js Y
590→    plane.origin.y  // domain Y -> Three.js Z
591→  );
592→
593→  return new THREE.Plane().setFromNormalAndCoplanarPoint(threeNormal, threeOrigin);
594→}
