  6→/** Ground plane at Z=0 (domain coords: XY plane) */
  7→export const GROUND_PLANE = Object.freeze({
  8→  origin: { x: 0, y: 0, z: 0 },
  9→  normal: { x: 0, y: 0, z: 1 },
 10→  up: { x: 0, y: 1, z: 0 },
 11→  uAxis: { x: 1, y: 0, z: 0 },
 12→  vAxis: { x: 0, y: 1, z: 0 },
 13→  sourcePartId: null,
 14→  sourceFace: null,
 15→});
