  1→/**
  2→ * Extrusion computation - pure functions for push/pull.
  3→ * Creates new part specs from face + distance.
  4→ */
  5→
  6→import { generateId } from '@/domain/ids';
  7→
  8→/**
  9→ * Get uniform dimensions for any part type.
 10→ */
 11→function getPartDimensions(part) {
 12→  switch (part.type) {
 13→    case 'panel':
 14→      return { width: part.width, depth: part.depth, height: part.thickness };
 15→    case 'leg':
 16→      return { width: part.width, depth: part.depth, height: part.height };
 17→    case 'frame': {
 18→      const w = part.axis === 'y' ? part.width : part.length;
 19→      const d = part.axis === 'y' ? part.length : part.width;
 20→      return { width: w, depth: d, height: part.height };
 21→    }
 22→    default:
 23→      return { width: part.width || 100, depth: part.depth || 100, height: part.height || part.thickness || 18 };
 24→  }
 25→}
 26→
 27→/**
 28→ * Compute a new part extruded from a face of an existing part.
 29→ *
 30→ * @param {Object} part - The source part
 31→ * @param {string} faceId - Face ID ('+x', '-x', '+y', '-y', '+z', '-z')
 32→ * @param {number} distance - Extrusion distance in mm (positive = outward)
 33→ * @returns {{ partOverrides: Object, constraint: Object }} New part overrides + constraint config
 34→ */
 35→export function computeExtrusionFromFace(part, faceId, distance) {
 36→  const dims = getPartDimensions(part);
 37→  const absDist = Math.abs(distance);
 38→  if (absDist < 1) return null;
 39→
 40→  const pos = { ...part.position };
 41→  let newWidth, newDepth, newThickness;
 42→
 43→  switch (faceId) {
 44→    case '+z': // top face - extrude upward
 45→      newWidth = dims.width;
 46→      newDepth = dims.depth;
 47→      newThickness = absDist;
 48→      pos.z = part.position.z + dims.height;
 49→      break;
 50→    case '-z': // bottom face - extrude downward
 51→      newWidth = dims.width;
 52→      newDepth = dims.depth;
 53→      newThickness = absDist;
 54→      pos.z = part.position.z - absDist;
 55→      break;
 56→    case '+x': // right face - extrude right
 57→      newWidth = absDist;
 58→      newDepth = dims.depth;
 59→      newThickness = dims.height;
 60→      pos.x = part.position.x + dims.width;
 61→      break;
 62→    case '-x': // left face - extrude left
 63→      newWidth = absDist;
 64→      newDepth = dims.depth;
 65→      newThickness = dims.height;
 66→      pos.x = part.position.x - absDist;
 67→      break;
 68→    case '+y': // back face - extrude back
 69→      newWidth = dims.width;
 70→      newDepth = absDist;
 71→      newThickness = dims.height;
 72→      pos.y = part.position.y + dims.depth;
 73→      break;
 74→    case '-y': // front face - extrude front
 75→      newWidth = dims.width;
 76→      newDepth = absDist;
 77→      newThickness = dims.height;
 78→      pos.y = part.position.y - absDist;
 79→      break;
 80→    default:
 81→      return null;
 82→  }
 83→
 84→  // Determine anchor mapping for constraint
 85→  const anchorMap = {
 86→    '+z': { sourceAnchor: 'bottom', targetAnchor: 'top' },
 87→    '-z': { sourceAnchor: 'top', targetAnchor: 'bottom' },
 88→    '+x': { sourceAnchor: 'left', targetAnchor: 'right' },
 89→    '-x': { sourceAnchor: 'right', targetAnchor: 'left' },
 90→    '+y': { sourceAnchor: 'front', targetAnchor: 'back' },
 91→    '-y': { sourceAnchor: 'back', targetAnchor: 'front' },
 92→  };
 93→
 94→  const anchors = anchorMap[faceId];
 95→
 96→  return {
 97→    partOverrides: {
 98→      name: 'Panel',
 99→      position: pos,
100→      width: newWidth,
101→      depth: newDepth,
102→      thickness: newThickness,
103→      assemblyId: part.assemblyId || null,
104→      objectId: part.objectId || null,
105→    },
106→    constraint: {
107→      type: 'attach_face',
108→      targetPartId: part.id,
109→      sourceAnchor: anchors.sourceAnchor,
110→      targetAnchor: anchors.targetAnchor,
111→      offset: 0,
112→    },
113→  };
114→}
