 1→export function snapToGrid(value, gridSize) {
 2→  return Math.round(value / gridSize) * gridSize;
 3→}
 4→
 5→export function snapPoint(point, gridSize) {
 6→  return {
 7→    x: snapToGrid(point.x, gridSize),
 8→    y: snapToGrid(point.y, gridSize),
 9→  };
10→}
11→
12→/**
13→ * Snap a 3D point to the nearest grid intersection on a given plane.
14→ * Projects to plane local coords, snaps, then converts back.
15→ */
16→export function snapPoint3d(point, gridSize, plane) {
17→  if (!plane) {
18→    return {
19→      x: snapToGrid(point.x, gridSize),
20→      y: snapToGrid(point.y, gridSize),
21→      z: snapToGrid(point.z, gridSize),
22→    };
23→  }
24→
25→  // Project point onto plane local coords
26→  const dx = point.x - plane.origin.x;
27→  const dy = point.y - plane.origin.y;
28→  const dz = point.z - plane.origin.z;
29→  const u = dx * plane.uAxis.x + dy * plane.uAxis.y + dz * plane.uAxis.z;
30→  const v = dx * plane.vAxis.x + dy * plane.vAxis.y + dz * plane.vAxis.z;
31→
32→  // Snap in local coords
33→  const su = snapToGrid(u, gridSize);
34→  const sv = snapToGrid(v, gridSize);
35→
36→  // Convert back to world
37→  return {
38→    x: plane.origin.x + su * plane.uAxis.x + sv * plane.vAxis.x,
39→    y: plane.origin.y + su * plane.uAxis.y + sv * plane.vAxis.y,
40→    z: plane.origin.z + su * plane.uAxis.z + sv * plane.vAxis.z,
41→  };
42→}
