  1→import * as THREE from 'three';
  2→
  3→const PREVIEW_COLOR = 0xB8860B;
  4→const PREVIEW_OPACITY = 0.35;
  5→const EDGE_COLOR = 0xB8860B;
  6→
  7→/**
  8→ * Three.js Group for push/pull extrusion preview.
  9→ * Shows a translucent box growing from the selected face.
 10→ */
 11→export function createExtrusionPreview() {
 12→  const group = new THREE.Group();
 13→  group.name = 'ExtrusionPreview';
 14→
 15→  let previewMesh = null;
 16→
 17→  const material = new THREE.MeshBasicMaterial({
 18→    color: PREVIEW_COLOR,
 19→    transparent: true,
 20→    opacity: PREVIEW_OPACITY,
 21→    depthWrite: false,
 22→  });
 23→
 24→  const edgeMaterial = new THREE.LineBasicMaterial({
 25→    color: EDGE_COLOR,
 26→    transparent: true,
 27→    opacity: 0.7,
 28→  });
 29→
 30→  function clear() {
 31→    if (previewMesh) {
 32→      group.remove(previewMesh);
 33→      previewMesh.traverse((child) => {
 34→        if (child.geometry) child.geometry.dispose();
 35→      });
 36→      previewMesh = null;
 37→    }
 38→  }
 39→
 40→  return {
 41→    group,
 42→
 43→    /**
 44→     * Update the extrusion preview.
 45→     * @param {Object} sourcePart - The part being extruded from
 46→     * @param {string} faceId - Face ID ('+x', '-x', '+y', '-y', '+z', '-z')
 47→     * @param {number} distance - Extrusion distance in mm
 48→     */
 49→    update(sourcePart, faceId, distance) {
 50→      clear();
 51→
 52→      if (!sourcePart || !faceId || Math.abs(distance) < 1) return;
 53→
 54→      const dims = getPartDimensions(sourcePart);
 55→      const pos = sourcePart.position;
 56→      const absDist = Math.abs(distance);
 57→
 58→      let boxW, boxH, boxD, cx, cy, cz;
 59→
 60→      switch (faceId) {
 61→        case '+z':
 62→          boxW = dims.width;
 63→          boxH = absDist;
 64→          boxD = dims.depth;
 65→          cx = pos.x + dims.width / 2;
 66→          cy = pos.z + dims.height + absDist / 2;
 67→          cz = pos.y + dims.depth / 2;
 68→          break;
 69→        case '-z':
 70→          boxW = dims.width;
 71→          boxH = absDist;
 72→          boxD = dims.depth;
 73→          cx = pos.x + dims.width / 2;
 74→          cy = pos.z - absDist / 2;
 75→          cz = pos.y + dims.depth / 2;
 76→          break;
 77→        case '+x':
 78→          boxW = absDist;
 79→          boxH = dims.height;
 80→          boxD = dims.depth;
 81→          cx = pos.x + dims.width + absDist / 2;
 82→          cy = pos.z + dims.height / 2;
 83→          cz = pos.y + dims.depth / 2;
 84→          break;
 85→        case '-x':
 86→          boxW = absDist;
 87→          boxH = dims.height;
 88→          boxD = dims.depth;
 89→          cx = pos.x - absDist / 2;
 90→          cy = pos.z + dims.height / 2;
 91→          cz = pos.y + dims.depth / 2;
 92→          break;
 93→        case '+y':
 94→          boxW = dims.width;
 95→          boxH = dims.height;
 96→          boxD = absDist;
 97→          cx = pos.x + dims.width / 2;
 98→          cy = pos.z + dims.height / 2;
 99→          cz = pos.y + dims.depth + absDist / 2;
100→          break;
101→        case '-y':
102→          boxW = dims.width;
103→          boxH = dims.height;
104→          boxD = absDist;
105→          cx = pos.x + dims.width / 2;
106→          cy = pos.z + dims.height / 2;
107→          cz = pos.y - absDist / 2;
108→          break;
109→        default:
110→          return;
111→      }
112→
113→      // Three.js coords: x=domain x, y=domain z, z=domain y
114→      const geometry = new THREE.BoxGeometry(boxW, boxH, boxD);
115→      const mesh = new THREE.Mesh(geometry, material);
116→      mesh.position.set(cx, cy, cz);
117→
118→      const edges = new THREE.EdgesGeometry(geometry);
119→      const lineSegments = new THREE.LineSegments(edges, edgeMaterial);
120→      mesh.add(lineSegments);
121→
122→      previewMesh = mesh;
123→      group.add(previewMesh);
124→    },
125→
126→    clear,
127→
128→    dispose() {
129→      clear();
130→      material.dispose();
131→      edgeMaterial.dispose();
132→    },
133→  };
134→}
135→
136→function getPartDimensions(part) {
137→  switch (part.type) {
138→    case 'panel':
139→      return { width: part.width, depth: part.depth, height: part.thickness };
140→    case 'leg':
141→      return { width: part.width, depth: part.depth, height: part.height };
142→    case 'frame': {
143→      const w = part.axis === 'y' ? part.width : part.length;
144→      const d = part.axis === 'y' ? part.length : part.width;
145→      return { width: w, depth: d, height: part.height };
146→    }
147→    default:
148→      return { width: part.width || 100, depth: part.depth || 100, height: part.height || part.thickness || 18 };
149→  }
150→}
