253→export function buildLegacyObjectTreeFromAssembly(project, assembly) {
254→  return {
255→    kind: 'object',
256→    id: assembly.objectId,
257→    objectId: assembly.objectId,
258→    name: assembly.name,
259→    role: assembly.templateType || assembly.category || 'object',
260→    children: [buildLegacyRootAssemblyNode(project, assembly)],
261→  };
262→}
