  7→function sketchEditorReducer(state, action) {
  8→  switch (action.type) {
  9→    case 'SET_TOOL':
 10→      return {
 11→        ...state,
 12→        activeTool: action.tool,
 13→        toolState: {},
 14→        selectedId: null,
 15→        selectedType: null,
 16→      };
 17→
 18→    case 'SELECT_OBJECT':
 19→      return {
 20→        ...state,
 21→        selectedId: action.id,
 22→        selectedType: action.objectType,
 23→      };
 24→
 25→    case 'DESELECT':
 26→      return {
 27→        ...state,
 28→        selectedId: null,
 29→        selectedType: null,
 30→      };
 31→
 32→    case 'UPDATE_TOOL_STATE':
 33→      return {
 34→        ...state,
 35→        toolState: { ...state.toolState, ...action.payload },
 36→      };
 37→
 38→    case 'SET_VIEWPORT': {
 39→      const vpKey = state.workspaceMode === 'sheet' ? 'sheetViewport' : 'modelViewport';
 40→      return {
 41→        ...state,
 42→        [vpKey]: { ...action.viewport },
 43→      };
 44→    }
 45→
 46→    case 'PAN': {
 47→      const vpKey = state.workspaceMode === 'sheet' ? 'sheetViewport' : 'modelViewport';
 48→      return {
 49→        ...state,
 50→        [vpKey]: {
 51→          ...state[vpKey],
 52→          panX: state[vpKey].panX + action.dx,
 53→          panY: state[vpKey].panY + action.dy,
 54→        },
 55→      };
 56→    }
 57→
 58→    case 'ZOOM': {
 59→      const { zoom, panX, panY } = action;
 60→      const vpKey = state.workspaceMode === 'sheet' ? 'sheetViewport' : 'modelViewport';
 61→      return {
 62→        ...state,
 63→        [vpKey]: { zoom, panX, panY },
 64→      };
 65→    }
 66→
 67→    case 'SET_WORKSPACE_MODE':
 68→      return {
 69→        ...state,
 70→        workspaceMode: action.workspaceMode,
 71→        selectedId: null,
 72→        selectedType: null,
 73→      };
 74→
 75→    case 'SET_ACTIVE_SHEET':
 76→      return {
 77→        ...state,
 78→        activeSheetId: action.sheetId,
 79→        selectedId: null,
 80→        selectedType: null,
 81→      };
 82→
 83→    case 'SET_VIEW':
 84→      return {
 85→        ...state,
 86→        activeView: action.view,
 87→      };
 88→
 89→    case 'SET_ACTIVE_ASSEMBLY':
 90→      return {
 91→        ...state,
 92→        activeAssemblyId: action.assemblyId,
 93→      };
 94→
 95→    case 'ENTER_ASSEMBLY_EDIT':
 96→      return {
 97→        ...state,
 98→        activeAssemblyId: action.assemblyId,
 99→        selectedId: action.assemblyId,
100→        selectedType: 'assembly',
101→      };
102→
103→    case 'TOGGLE_GRID':
104→      return { ...state, showGrid: !state.showGrid };
105→
106→    case 'TOGGLE_SNAP':
107→      return { ...state, snapEnabled: !state.snapEnabled };
108→
109→    case 'SET_STATUS_MESSAGE':
110→      return { ...state, statusMessage: action.message };
111→
112→    case 'CLEAR_STATUS_MESSAGE':
113→      if (!state.statusMessage) return state;
114→      return { ...state, statusMessage: null };
115→
116→    case 'DISMISS_EMPTY_STATE':
117→      return { ...state, emptyStateDismissed: true };
118→
119→    case 'TOGGLE_MAXIMIZE_PANEL':
120→      return { ...state, maximizedPanel: state.maximizedPanel === action.panel ? null : action.panel };
121→
122→    case 'SET_DRAWING_PLANE':
123→      return { ...state, drawingPlane: action.plane };
124→
125→    case 'RESET_DRAWING_PLANE':
126→      return { ...state, drawingPlane: null };
127→
128→    default:
129→      return state;
130→  }
131→}
