134→  return {
135→    activeTool: SKETCH_TOOLS.SELECT,
136→    selectedId: null,
137→    selectedType: null,
138→    toolState: {},
139→    modelViewport: { panX: 400, panY: 300, zoom: DEFAULT_SKETCH_ZOOM },
140→    sheetViewport: { panX: 400, panY: 300, zoom: 2.0 },
141→    workspaceMode: 'model',
142→    activeSheetId: null,
143→    activeView: 'top',
144→    activeAssemblyId: null,
