17→export function materializePartDefinition(partDefinition, overrides = {}) {
18→  const factory = PART_FACTORIES[partDefinition.type];
19→  if (!factory) {
20→    throw new Error(`Unsupported part type: ${partDefinition.type}`);
21→  }
22→
23→  return factory({
24→    name: partDefinition.name,
25→    role: partDefinition.role,
26→    ...partDefinition.props,
27→    ...overrides,
28→  });
