  1→/**
  2→ * Drawing plane geometry - pure functions, no React/Three.js dependencies.
  3→ * A drawing plane defines a 2D coordinate system embedded in 3D space.
  4→ */
  5→
  6→/** Ground plane at Z=0 (domain coords: XY plane) */
  7→export const GROUND_PLANE = Object.freeze({
  8→  origin: { x: 0, y: 0, z: 0 },
  9→  normal: { x: 0, y: 0, z: 1 },
 10→  up: { x: 0, y: 1, z: 0 },
 11→  uAxis: { x: 1, y: 0, z: 0 },
 12→  vAxis: { x: 0, y: 1, z: 0 },
 13→  sourcePartId: null,
 14→  sourceFace: null,
 15→});
 16→
 17→/**
 18→ * Given a part and a face ID, compute a drawing plane sitting on that face.
 19→ * Face IDs: '+x', '-x', '+y', '-y', '+z', '-z'
 20→ */
 21→export function faceToDrawingPlane(part, faceId) {
 22→  const { position } = part;
 23→  const dims = getPartDimensions(part);
 24→
 25→  // Center of the part in domain coords
 26→  const cx = position.x + dims.width / 2;
 27→  const cy = position.y + dims.depth / 2;
 28→  const cz = position.z + dims.height / 2;
 29→
 30→  let origin, normal, up, uAxis, vAxis;
 31→
 32→  switch (faceId) {
 33→    case '+z': // top face
 34→      origin = { x: position.x, y: position.y, z: position.z + dims.height };
 35→      normal = { x: 0, y: 0, z: 1 };
 36→      uAxis = { x: 1, y: 0, z: 0 };
 37→      vAxis = { x: 0, y: 1, z: 0 };
 38→      up = { x: 0, y: 1, z: 0 };
 39→      break;
 40→    case '-z': // bottom face
 41→      origin = { x: position.x, y: position.y, z: position.z };
 42→      normal = { x: 0, y: 0, z: -1 };
 43→      uAxis = { x: 1, y: 0, z: 0 };
 44→      vAxis = { x: 0, y: 1, z: 0 };
 45→      up = { x: 0, y: 1, z: 0 };
 46→      break;
 47→    case '+x': // right face
 48→      origin = { x: position.x + dims.width, y: position.y, z: position.z };
 49→      normal = { x: 1, y: 0, z: 0 };
 50→      uAxis = { x: 0, y: 1, z: 0 };
 51→      vAxis = { x: 0, y: 0, z: 1 };
 52→      up = { x: 0, y: 0, z: 1 };
 53→      break;
 54→    case '-x': // left face
 55→      origin = { x: position.x, y: position.y, z: position.z };
 56→      normal = { x: -1, y: 0, z: 0 };
 57→      uAxis = { x: 0, y: 1, z: 0 };
 58→      vAxis = { x: 0, y: 0, z: 1 };
 59→      up = { x: 0, y: 0, z: 1 };
 60→      break;
 61→    case '+y': // back face
 62→      origin = { x: position.x, y: position.y + dims.depth, z: position.z };
 63→      normal = { x: 0, y: 1, z: 0 };
 64→      uAxis = { x: 1, y: 0, z: 0 };
 65→      vAxis = { x: 0, y: 0, z: 1 };
 66→      up = { x: 0, y: 0, z: 1 };
 67→      break;
 68→    case '-y': // front face
 69→      origin = { x: position.x, y: position.y, z: position.z };
 70→      normal = { x: 0, y: -1, z: 0 };
 71→      uAxis = { x: 1, y: 0, z: 0 };
 72→      vAxis = { x: 0, y: 0, z: 1 };
 73→      up = { x: 0, y: 0, z: 1 };
 74→      break;
 75→    default:
 76→      return { ...GROUND_PLANE };
 77→  }
 78→
 79→  return { origin, normal, up, uAxis, vAxis, sourcePartId: part.id, sourceFace: faceId };
 80→}
 81→
 82→/**
 83→ * Project a 3D point onto a plane, returning local (u, v) coordinates.
 84→ */
 85→export function projectToPlane(point3d, plane) {
 86→  const dx = point3d.x - plane.origin.x;
 87→  const dy = point3d.y - plane.origin.y;
 88→  const dz = point3d.z - plane.origin.z;
 89→  const u = dx * plane.uAxis.x + dy * plane.uAxis.y + dz * plane.uAxis.z;
 90→  const v = dx * plane.vAxis.x + dy * plane.vAxis.y + dz * plane.vAxis.z;
 91→  return { u, v };
 92→}
 93→
 94→/**
 95→ * Convert local (u, v) on a plane back to 3D world coordinates.
 96→ */
 97→export function planeLocalToWorld(u, v, plane) {
 98→  return {
 99→    x: plane.origin.x + u * plane.uAxis.x + v * plane.vAxis.x,
100→    y: plane.origin.y + u * plane.uAxis.y + v * plane.vAxis.y,
101→    z: plane.origin.z + u * plane.uAxis.z + v * plane.vAxis.z,
102→  };
103→}
104→
105→/**
106→ * Map a Three.js face normal (approximate) to a canonical face ID.
107→ * Three.js coords: x=domain x, y=domain z, z=domain y
108→ */
109→export function identifyFace(threeNormal) {
110→  const ax = Math.abs(threeNormal.x);
111→  const ay = Math.abs(threeNormal.y);
112→  const az = Math.abs(threeNormal.z);
113→
114→  if (ay >= ax && ay >= az) {
115→    return threeNormal.y > 0 ? '+z' : '-z'; // Three.js Y = domain Z
116→  }
117→  if (ax >= ay && ax >= az) {
118→    return threeNormal.x > 0 ? '+x' : '-x';
119→  }
120→  return threeNormal.z > 0 ? '+y' : '-y'; // Three.js Z = domain Y
121→}
122→
123→/**
124→ * Get uniform dimensions for any part type.
125→ */
126→function getPartDimensions(part) {
127→  switch (part.type) {
128→    case 'panel':
129→      return { width: part.width, depth: part.depth, height: part.thickness };
130→    case 'leg':
131→      return { width: part.width, depth: part.depth, height: part.height };
132→    case 'frame': {
133→      const w = part.axis === 'y' ? part.width : part.length;
134→      const d = part.axis === 'y' ? part.length : part.width;
135→      return { width: w, depth: d, height: part.height };
136→    }
137→    default:
138→      return { width: part.width || 100, depth: part.depth || 100, height: part.height || part.thickness || 18 };
139→  }
140→}
