  1→import { createPanel, createLeg, createFrame, createCutout, createHole } from '../../domain/partModels';
  2→import { viewToModelPosition, viewToModelExtents } from '../../domain/viewProjection';
  3→import { snapPoint } from '../snap';
  4→import { SKETCH_GRID_MINOR } from '../../domain/defaults';
  5→
  6→const partFactories = {
  7→  panel: createPanel,
  8→  leg: createLeg,
  9→  frame: createFrame,
 10→  cutout: createCutout,
 11→  hole: createHole,
 12→};
 13→
 14→export function createPartPlaceHandler({ dispatch, editorDispatch, activeView, activeAssemblyId, partType, selectedId, project, snapEnabled }) {
 15→  const needsParent = partType === 'cutout' || partType === 'hole';
 16→
 17→  return {
 18→    onMouseDown(modelPos, e, toolState) {
 19→      if (e.button !== 0) return;
 20→
 21→      if (activeAssemblyId) {
 22→        const activeAssembly = project.assemblies.find((assembly) => assembly.id === activeAssemblyId);
 23→        const managedObject = activeAssembly?.objectId
 24→          ? project.objects.find((object) => object.id === activeAssembly.objectId && object.editingPolicy === 'parametric')
 25→          : null;
 26→        if (managedObject) {
 27→          editorDispatch({
 28→            type: 'SET_STATUS_MESSAGE',
 29→            message: 'Detach the object before manually adding parts to a generated assembly.',
 30→          });
 31→          return;
 32→        }
 33→      }
 34→
 35→      if (needsParent) {
 36→        const parentPart = selectedId ? project.parts.find((p) => p.id === selectedId) : null;
 37→        if (!parentPart || parentPart.type !== 'panel') {
 38→          editorDispatch({
 39→            type: 'SET_STATUS_MESSAGE',
 40→            message: `Select a panel first to place a ${partType}.`,
 41→          });
 42→          return;
 43→        }
 44→      }
 45→
 46→      const pos = snapEnabled ? snapPoint(modelPos, SKETCH_GRID_MINOR) : modelPos;
 47→
 48→      editorDispatch({
 49→        type: 'UPDATE_TOOL_STATE',
 50→        payload: {
 51→          drawing: true,
 52→          startPos: { x: pos.x, y: pos.y },
 53→          currentPos: { x: pos.x, y: pos.y },
 54→        },
 55→      });
 56→    },
 57→
 58→    onMouseMove(modelPos, e, toolState) {
 59→      if (!toolState.drawing) return;
 60→
 61→      editorDispatch({
 62→        type: 'UPDATE_TOOL_STATE',
 63→        payload: {
 64→          currentPos: { x: modelPos.x, y: modelPos.y },
 65→        },
 66→      });
 67→    },
 68→
 69→    onMouseUp(modelPos, e, toolState) {
 70→      if (!toolState.drawing || !toolState.startPos) return;
 71→
 72→      const endPos = snapEnabled ? snapPoint(modelPos, SKETCH_GRID_MINOR) : modelPos;
 73→
 74→      const x = Math.min(toolState.startPos.x, endPos.x);
 75→      const y = Math.min(toolState.startPos.y, endPos.y);
 76→      const svgW = Math.abs(endPos.x - toolState.startPos.x);
 77→      const svgH = Math.abs(endPos.y - toolState.startPos.y);
 78→
 79→      const minSize = 10; // mm
 80→      if (svgW > minSize && svgH > minSize) {
 81→        const position = viewToModelPosition(x, y, activeView);
 82→        const extents = viewToModelExtents(svgW, svgH, activeView, partType);
 83→
 84→        const factory = partFactories[partType];
 85→        if (!factory) return;
 86→
 87→        const overrides = {
 88→          position,
 89→          ...extents,
 90→        };
 91→
 92→        if (needsParent) {
 93→          overrides.parentId = selectedId;
 94→        }
 95→
 96→        const part = factory(overrides);
 97→
 98→        dispatch({ type: 'PART_ADD', part });
 99→
100→        if (activeAssemblyId) {
101→          dispatch({ type: 'ASSEMBLY_ADD_PART', assemblyId: activeAssemblyId, partId: part.id });
102→        }
103→
104→        editorDispatch({
105→          type: 'SET_STATUS_MESSAGE',
106→          message: `${partType}: ${Math.round(svgW)} x ${Math.round(svgH)} mm`,
107→        });
