 12→/**
 13→ * 3D rectangle drawing handler.
 14→ * Click-drag on the active drawing plane to create a part.
 15→ */
 16→export function createDrawRectHandler3d({ dispatch, editorDispatch, project, activeAssemblyId, partType, snapEnabled, drawingPlane }) {
 17→  const plane = drawingPlane || GROUND_PLANE;
 18→
 19→  return {
 20→    onPointerDown(intersection, e, toolState, viewport) {
 21→      if (e.button !== 0) return;
 22→
 23→      // Get point on drawing plane
 24→      const planePoint = intersection?.drawingPlanePoint;
 25→      if (!planePoint) return;
 26→
 27→      // Project to plane local coords
 28→      const local = projectToPlane(planePoint, plane);
 29→
 30→      const snapped = snapEnabled
 31→        ? { u: snapToGrid(local.u, SKETCH_GRID_MINOR), v: snapToGrid(local.v, SKETCH_GRID_MINOR) }
 32→        : local;
 33→
 34→      editorDispatch({
 35→        type: 'UPDATE_TOOL_STATE',
 36→        payload: {
 37→          drawing: true,
 38→          startLocal: snapped,
 39→          currentLocal: snapped,
 40→          startWorld: planeLocalToWorld(snapped.u, snapped.v, plane),
 41→          currentWorld: planeLocalToWorld(snapped.u, snapped.v, plane),
 42→        },
 43→      });
 44→    },
 45→
 46→    onPointerMove(intersection, e, toolState, viewport) {
 47→      if (!toolState.drawing) return;
 48→
 49→      const planePoint = intersection?.drawingPlanePoint;
 50→      if (!planePoint) return;
 51→
 52→      const local = projectToPlane(planePoint, plane);
 53→      const snapped = snapEnabled
 54→        ? { u: snapToGrid(local.u, SKETCH_GRID_MINOR), v: snapToGrid(local.v, SKETCH_GRID_MINOR) }
 55→        : local;
 56→
 57→      editorDispatch({
 58→        type: 'UPDATE_TOOL_STATE',
 59→        payload: {
 60→          currentLocal: snapped,
 61→          currentWorld: planeLocalToWorld(snapped.u, snapped.v, plane),
 62→        },
 63→      });
 64→    },
 65→
 66→    onPointerUp(intersection, e, toolState, viewport) {
 67→      if (!toolState.drawing || !toolState.startLocal) return;
 68→
 69→      const endPoint = intersection?.drawingPlanePoint;
 70→      if (endPoint) {
 71→        const local = projectToPlane(endPoint, plane);
 72→        var endLocal = snapEnabled
 73→          ? { u: snapToGrid(local.u, SKETCH_GRID_MINOR), v: snapToGrid(local.v, SKETCH_GRID_MINOR) }
 74→          : local;
 75→      } else {
 76→        var endLocal = toolState.currentLocal;
 77→      }
 78→
 79→      const uSize = Math.abs(endLocal.u - toolState.startLocal.u);
 80→      const vSize = Math.abs(endLocal.v - toolState.startLocal.v);
 81→
 82→      const minSize = 10; // mm
 83→      if (uSize > minSize && vSize > minSize) {
 84→        const minU = Math.min(toolState.startLocal.u, endLocal.u);
 85→        const minV = Math.min(toolState.startLocal.v, endLocal.v);
 86→
 87→        // Convert plane-local corner to world position
 88→        const worldPos = planeLocalToWorld(minU, minV, plane);
 89→
 90→        // Map plane dimensions to part dimensions based on plane orientation
 91→        const overrides = computePartOverrides(plane, worldPos, uSize, vSize, partType);
 92→
 93→        if (plane.sourcePartId) {
 94→          const sourcePart = project.parts.find((p) => p.id === plane.sourcePartId);
 95→          if (sourcePart) {
 96→            overrides.assemblyId = sourcePart.assemblyId || null;
 97→            overrides.objectId = sourcePart.objectId || null;
 98→          }
 99→        }
100→
101→        const factory = partFactories[partType];
102→        if (factory) {
103→          const part = factory(overrides);
104→          dispatch({ type: 'PART_ADD', part });
105→
106→          if (activeAssemblyId) {
107→            dispatch({ type: 'ASSEMBLY_ADD_PART', assemblyId: activeAssemblyId, partId: part.id });
108→          }
109→
110→          editorDispatch({
111→            type: 'SET_STATUS_MESSAGE',
112→            message: `${partType}: ${Math.round(uSize)} x ${Math.round(vSize)} mm`,
113→          });
114→        }
115→      }
116→
117→      editorDispatch({
118→        type: 'UPDATE_TOOL_STATE',
119→        payload: {
120→          drawing: false,
121→          startLocal: null,
122→          currentLocal: null,
123→          startWorld: null,
124→          currentWorld: null,
125→        },
126→      });
127→    },
128→
129→    onKeyDown(e) {
130→      if (e.key === 'Escape') {
131→        editorDispatch({
132→          type: 'UPDATE_TOOL_STATE',
133→          payload: {
134→            drawing: false,
135→            startLocal: null,
136→            currentLocal: null,
137→            startWorld: null,
138→            currentWorld: null,
139→          },
140→        });
141→      }
142→    },
143→
144→    getCursor() {
145→      return 'crosshair';
146→    },
147→  };
148→}
