  1→import * as THREE from 'three';
  2→
  3→const WOOD_COLOR = 0xD2B48C;
  4→const SELECTED_TINT = 0xB8860B;
  5→const EDGE_COLOR = 0x333333;
  6→
  7→/**
  8→ * Face index mapping for BoxGeometry.
  9→ * Three.js BoxGeometry has 6 groups (2 triangles each):
 10→ * group 0: +x, group 1: -x, group 2: +y, group 3: -y, group 4: +z, group 5: -z
 11→ */
 12→const BOX_FACE_IDS = ['+x', '-x', '+y', '-y', '+z', '-z'];
 13→
 14→function createBoxMesh(width, height, depth, color) {
 15→  const geometry = new THREE.BoxGeometry(width, height, depth);
 16→  const material = new THREE.MeshStandardMaterial({
 17→    color,
 18→    roughness: 0.7,
 19→    metalness: 0.05,
 20→  });
 21→  const mesh = new THREE.Mesh(geometry, material);
 22→  mesh.userData.faceIds = BOX_FACE_IDS;
 23→  return mesh;
 24→}
 25→
 26→function createCylinderMesh(diameter, height, color) {
 27→  const geometry = new THREE.CylinderGeometry(diameter / 2, diameter / 2, height, 16);
 28→  const material = new THREE.MeshStandardMaterial({
 29→    color,
 30→    roughness: 0.7,
 31→    metalness: 0.05,
 32→  });
 33→  return new THREE.Mesh(geometry, material);
 34→}
 35→
 36→function addEdges(mesh) {
 37→  const edges = new THREE.EdgesGeometry(mesh.geometry);
 38→  const line = new THREE.LineSegments(
 39→    edges,
 40→    new THREE.LineBasicMaterial({ color: EDGE_COLOR, transparent: true, opacity: 0.3 })
 41→  );
 42→  mesh.add(line);
 43→}
 44→
 45→function createPanelMesh(part, isSelected) {
 46→  const color = isSelected ? SELECTED_TINT : WOOD_COLOR;
 47→  const mesh = createBoxMesh(part.width, part.thickness, part.depth, color);
 48→  // Three.js: x = part.x + w/2, y = part.z + h/2, z = part.y + d/2
 49→  mesh.position.set(
 50→    part.position.x + part.width / 2,
 51→    part.position.z + part.thickness / 2,
 52→    part.position.y + part.depth / 2
 53→  );
 54→  addEdges(mesh);
 55→  return mesh;
 56→}
 57→
 58→function createLegMesh(part, isSelected) {
 59→  const color = isSelected ? SELECTED_TINT : 0x8B7355;
 60→
 61→  if (part.profile === 'round') {
 62→    const mesh = createCylinderMesh(part.width, part.height, color);
 63→    mesh.position.set(
 64→      part.position.x + part.width / 2,
 65→      part.position.z + part.height / 2,
 66→      part.position.y + part.depth / 2
 67→    );
 68→    addEdges(mesh);
 69→    return mesh;
 70→  }
 71→
 72→  const mesh = createBoxMesh(part.width, part.height, part.depth, color);
 73→  mesh.position.set(
 74→    part.position.x + part.width / 2,
 75→    part.position.z + part.height / 2,
 76→    part.position.y + part.depth / 2
 77→  );
 78→  addEdges(mesh);
 79→  return mesh;
 80→}
 81→
 82→function createFrameMesh(part, isSelected) {
 83→  const color = isSelected ? SELECTED_TINT : 0xA0522D;
 84→  let w, h, d;
 85→
 86→  if (part.axis === 'y') {
 87→    w = part.width;
 88→    h = part.height;
 89→    d = part.length;
 90→  } else {
 91→    w = part.length;
 92→    h = part.height;
 93→    d = part.width;
 94→  }
 95→
 96→  const mesh = createBoxMesh(w, h, d, color);
 97→  mesh.position.set(
 98→    part.position.x + w / 2,
 99→    part.position.z + h / 2,
100→    part.position.y + d / 2
101→  );
102→  addEdges(mesh);
103→  return mesh;
104→}
105→
106→function isPartSelected(part, selection) {
107→  if (!selection) return false;
108→  if (selection.selectedType === 'object') return part.objectId === selection.selectedId;
109→  return part.id === selection.selectedId;
110→}
111→
112→export function buildSketchPreviewRoot(parts, selection) {
113→  const root = new THREE.Group();
114→
115→  for (const part of parts) {
116→    // Skip dimension, cutout, hole in 3D for V1
117→    if (part.type === 'dimension' || part.type === 'cutout' || part.type === 'hole') continue;
118→
119→    const isSelected = isPartSelected(part, selection);
120→    let mesh;
121→
122→    switch (part.type) {
123→      case 'panel':
124→        mesh = createPanelMesh(part, isSelected);
125→        break;
126→      case 'leg':
127→        mesh = createLegMesh(part, isSelected);
128→        break;
129→      case 'frame':
130→        mesh = createFrameMesh(part, isSelected);
131→        break;
132→      default:
133→        continue;
134→    }
135→
136→    if (mesh) {
137→      const previewTarget = part.objectId
138→        ? { sourceId: part.objectId, kind: 'object' }
139→        : { sourceId: part.id, kind: 'part' };
140→      mesh.userData.previewTarget = previewTarget;
141→      root.add(mesh);
142→    }
143→  }
144→
145→  return root;
146→}
