### 7. Modifications to `src/modules/sketch/editor/snap.js` -- Unified Smart Snap

Add a new function that chains inference snapping with grid snapping:

```javascript
import { findNearestInference, findNearestInferenceOnPlane, computeWorldThreshold } from './inferenceEngine';

export function smartSnap3d(point, options) {
  const {
    inferencePoints,
    gridSize,
    plane,            // optional: drawing plane for 2D-constrained snapping
    camera,           // Three.js camera for screen-space threshold
    domElement,       // renderer DOM element
    screenThresholdPx = 15,
  } = options;

  // 1. Compute world-space threshold from screen pixels
  const thresholdMm = computeWorldThreshold(camera, domElement, screenThresholdPx, point);

  // 2. Try inference snap first
  let inferenceResult;
  if (plane) {
    inferenceResult = findNearestInferenceOnPlane(point, inferencePoints, plane, thresholdMm);
  } else {
    inferenceResult = findNearestInference(point, inferencePoints, thresholdMm);
  }

  if (inferenceResult) {
    return inferenceResult; // { point, inference, distance, snapped: true }
  }

  // 3. Fall back to grid snap
  const gridPoint = plane
    ? snapPoint3dOnPlane(point, gridSize, plane)  // existing snapPoint3d logic
    : snapPoint3d(point, gridSize);

  return { point: gridPoint, inference: null, distance: 0, snapped: false };
}
```

The existing `snapToGrid`, `snapPoint`, `snapPoint3d` functions remain unchanged for backward compatibility. The new `smartSnap3d` is the only function handlers need to call.

